    OP_REQUIRES_OK_ASYNC(
        context, DoMatrixTranspose(device, rhs, &transposed_rhs), done);
  } else {
    device.memcpy(transposed_rhs.flat<Scalar>().data(),
                  rhs.flat<Scalar>().data(),
                  rhs.NumElements() * sizeof(Scalar));
